import sys, types, threading, time
import pytest

def test_widened(monkeypatch):
    from assay_engine.persistence import checkpoint as cp
    state = {"setup_on": [], "pools": []}

    class FakeConn:
        def execute(self, sql, params=None):
            pass
    class FakePool:
        check_connection = staticmethod(lambda *a, **k: None)
        def __init__(self, conn_str, **kw):
            self.conn_str = conn_str; self._conn = FakeConn(); state["pools"].append(self)
        def connection(self):
            conn = self._conn
            class _Ctx:
                def __enter__(s): return conn
                def __exit__(s,*a): return False
            return _Ctx()
        def close(self): pass
    class FakeSaver:
        def __init__(self, arg): self.arg = arg
        def setup(self):
            time.sleep(0.05)  # widen the race window
            state["setup_on"].append(id(self.arg))

    def _mod(name, **attrs):
        m = types.ModuleType(name)
        for k,v in attrs.items(): setattr(m,k,v)
        monkeypatch.setitem(sys.modules, name, m); return m
    _mod("langgraph"); _mod("langgraph.checkpoint")
    _mod("langgraph.checkpoint.postgres", PostgresSaver=FakeSaver)
    _mod("langgraph.checkpoint.memory", MemorySaver=type("M",(),{}))
    _mod("psycopg"); _mod("psycopg.rows", dict_row=object())
    _mod("psycopg_pool", ConnectionPool=FakePool)
    monkeypatch.setattr(cp, "_INITIALIZED_CONN_STRS", set())
    monkeypatch.setattr(cp, "_OPEN_POOLS", [])
    monkeypatch.setattr(cp, "_atexit_registered", False)
    monkeypatch.setattr(cp, "_CONN_INIT_LOCKS", {})
    monkeypatch.setattr(cp, "_POOLS_BY_CONN", {})
    monkeypatch.setattr(cp, "atexit", types.SimpleNamespace(register=lambda fn: None))
    monkeypatch.setenv("ASSAY_POSTGRES_URL", "postgresql://localhost:5432/assay")

    barrier = threading.Barrier(8)
    def worker():
        barrier.wait(); cp.get_checkpointer()
    ts = [threading.Thread(target=worker) for _ in range(8)]
    for t in ts: t.start()
    for t in ts: t.join(5)
    assert len(state["setup_on"]) == 1, f"setup ran {len(state['setup_on'])} times"
    assert len(state["pools"]) == 1
EOF
